-- ── Verificación ───────────────────────────────────────────────────────────
SELECT c.acronimo, COUNT(*) AS total
FROM carrera_materia cm
JOIN carrera c ON c.id_carrera = cm.id_carrera
GROUP BY c.acronimo ORDER BY c.acronimo;
